solution_code:
#include <iostream>

consteval unsigned int bit_width(unsigned int n) {
    if (n == 0) return 0;
    unsigned int count = 0;
    while (n > 0) {
        ++count;
        n >>= 1;
    }
    return count;
}

constexpr unsigned int bit_width_cx(unsigned int n) {
    if (n == 0) return 0;
    unsigned int count = 0;
    while (n > 0) {
        ++count;
        n >>= 1;
    }
    return count;
}

int main() {
    constexpr unsigned int ct = bit_width(255);
    std::cout << "Compile-time: " << ct << "\n";

    unsigned int x;
    std::cin >> x;
    std::cout << "Runtime: " << bit_width_cx(x) << "\n";
    return 0;
}

